fun solve(nums: Array<Long>, k: Long): Long {
    val N = nums.size
    if (k == 0L) return 0L
    if (k > N / 2) return -1L

    // Calculate cost C[i] to make nums[i] a peak using original neighbors
    val C = LongArray(N)
    for (i in 0 until N) {
        val leftIndex = (i - 1 + N) % N
        val rightIndex = (i + 1) % N

        val L = nums[leftIndex]
        val R = nums[rightIndex]

        val requiredValue = maxOf(L, R) + 1L

        C[i] = maxOf(0L, requiredValue - nums[i])
    }

    val INF = 1_000_000_000_000_000_000L // Sufficiently large infinity

    var minCost = INF

    // --- Scenario A: Index 0 is NOT selected ---
    // DP_A[i][j][t]: Min cost up to index i, selecting j peaks, where t=1 if i is selected, t=0 otherwise.
    // Size: N x (K+1) x 2
    val dpA = Array(N) { Array(k.toInt() + 1) { LongArray(2) { INF } } }

    dpA[0][0][0] = 0L

    for (i in 1 until N) {
        for (j in 0..k.toInt()) {
            // Case t=0: i is NOT selected
            // Can transition from i-1 being taken or not taken
            dpA[i][j][0] = minOf(dpA[i - 1][j][0], dpA[i - 1][j][1])

            // Case t=1: i IS selected
            if (j > 0) {
                // Must transition from i-1 NOT selected
                dpA[i][j][1] = dpA[i - 1][j - 1][0] + C[i]
            }
        }
    }

    // Result A: N-1 can be selected or not selected, as 0 was not selected.
    minCost = minOf(minCost, dpA[N - 1][k.toInt()][0])
    minCost = minOf(minCost, dpA[N - 1][k.toInt()][1])

    // --- Scenario B: Index 0 IS selected ---
    // dpB must handle the constraint that index 1 cannot be selected.
    val dpB = Array(N) { Array(k.toInt() + 1) { LongArray(2) { INF } } }

    dpB[0][1][1] = C[0]

    for (i in 1 until N) {
        for (j in 0..k.toInt()) {
            // Case t=0: i is NOT selected
            dpB[i][j][0] = minOf(dpB[i - 1][j][0], dpB[i - 1][j][1])

            // Case t=1: i IS selected
            if (j > 0) {
                // Constraint: If 0 is selected, 1 cannot be selected.
                if (i == 1) {
                    // dpB[1][j][1] remains INF
